import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/prisma";
import PDFDocument from "pdfkit";
import { Document, Packer, Paragraph, TextRun, AlignmentType, Header, Footer, BorderStyle, ImageRun } from "docx";
import path from "path";
import fs from "fs";

// ─── Constants ───────────────────────────────────────────────────────────────

const EXPIRY_HOURS = 72;
const DISCLAIMER =
    "This document is an Automated Technology generated summary for informational purposes only and does not constitute legal, financial, or professional advice.";

// Helper function placeholder (assuming you have this defined in your file)
// function stripMarkdown(text: string): string {
//     return text.replace(/(#|\*|_|\[|\]|\(|\))/g, "");
// }

// Ensure you have your generatePDF and generateDOCX functions defined below this in your actual file

export async function POST(req: NextRequest, { params }: { params: Promise<{ format: string }> }) {
    try {
        const resolvedParams = await params;
        const format = resolvedParams.format.toLowerCase();

        // Extract data from the POST body instead of URL params
        const body = await req.json();
        const { job_id, token, breakdownText } = body;

        if (!job_id || !token) {
            return NextResponse.json({ error: "Missing job ID or access token." }, { status: 400 });
        }

        if (!breakdownText) {
            return NextResponse.json({ error: "Missing breakdown text." }, { status: 400 });
        }

        if (!["pdf", "docx", "txt"].includes(format)) {
            return NextResponse.json({ error: "Invalid format requested." }, { status: 400 });
        }

        // ── 1. Retrieve job & verify token via Prisma ──
        const job = await prisma.job.findFirst({
            where: {
                id: job_id,
                access_token: token,
            },
        });

        if (!job) {
            return NextResponse.json({ error: "Invalid job reference or access token." }, { status: 403 });
        }

        // ── 2. Enforce paid content guard ──
        if (job.status !== "COMPLETED" || !job.stripe_payment_intent_id) {
            return NextResponse.json({ error: "Detailed breakdown not available or payment not confirmed." }, { status: 403 });
        }

        // ── 3. Enforce 72-hour expiry ──
        // Fallback to updated_at if processed_at is null
        const processedAtDate = job.processed_at || job.updated_at;
        const hoursSinceCompletion = (Date.now() - processedAtDate.getTime()) / (1000 * 60 * 60);

        if (hoursSinceCompletion > EXPIRY_HOURS) {
            return NextResponse.json({ error: "Download link has expired. Links expire 72 hours after completion." }, { status: 410 });
        }

        const referenceId: string = job.reference_id || job.id;
        const dateStr: string = processedAtDate.toLocaleDateString("en-GB");

        // ── 4. Generate by format ──

        if (format === "txt") {
            const txtContent = [
                "ExplainMyLetter Breakdown",
                `Reference: ${referenceId}`,
                `Date: ${dateStr}`,
                "",
                stripMarkdown(breakdownText),
                "",
                "---",
                DISCLAIMER,
            ].join("\n");

            return new NextResponse(txtContent, {
                headers: {
                    "Content-Type": "text/plain; charset=utf-8",
                    "Content-Disposition": `attachment; filename="breakdown_${referenceId}.txt"`,
                },
            });
        }

        if (format === "pdf") {
            // @ts-ignore - Assuming generatePDF is defined in your file
            const pdfBuffer = await generatePDF(breakdownText, referenceId, dateStr);
            return new NextResponse(new Uint8Array(pdfBuffer), {
                headers: {
                    "Content-Type": "application/pdf",
                    "Content-Disposition": `attachment; filename="breakdown_${referenceId}.pdf"`,
                },
            });
        }

        if (format === "docx") {
            // @ts-ignore - Assuming generateDOCX is defined in your file
            const docxBuffer = await generateDOCX(breakdownText, referenceId, dateStr);
            return new NextResponse(new Uint8Array(docxBuffer), {
                headers: {
                    "Content-Type": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
                    "Content-Disposition": `attachment; filename="breakdown_${referenceId}.docx"`,
                },
            });
        }

        return NextResponse.json({ error: "Unhandled format." }, { status: 400 });
    } catch (error) {
        console.error("[download/route]", error);
        return NextResponse.json({ error: "Failed to generate document." }, { status: 500 });
    }
}

// ─── Shared markdown line parser ──────────────────────────────────────────────

function stripInline(line: string): string {
    return line
        .replace(/\*\*(.+?)\*\*/g, "$1")
        .replace(/\*(.+?)\*/g, "$1")
        .replace(/`(.+?)`/g, "$1");
}
function stripMarkdown(text: string): string {
    return text
        .split("\n")
        .map((line) => {
            const trimmed = line.trimEnd();
            // Remove heading markers
            if (/^#{1,6}\s+/.test(trimmed)) return trimmed.replace(/^#{1,6}\s+/, "");
            // Remove bullet markers
            if (/^[-*]\s+/.test(trimmed)) return "• " + trimmed.slice(2);
            // Remove ordered list markers (keep the number)
            const ol = trimmed.match(/^(\d+)\.\s+(.*)/);
            if (ol) return `${ol[1]}. ${ol[2]}`;
            // Remove horizontal rules
            if (/^---+$/.test(trimmed)) return "";
            // Strip inline markdown
            return trimmed
                .replace(/\*\*(.+?)\*\*/g, "$1")
                .replace(/\*(.+?)\*/g, "$1")
                .replace(/`(.+?)`/g, "$1");
        })
        .join("\n");
}

function parseInlineDocx(line: string, baseSize = 22): TextRun[] {
    const runs: TextRun[] = [];
    const regex = /\*\*(.+?)\*\*|\*(.+?)\*/g;
    let last = 0;
    let match: RegExpExecArray | null;

    while ((match = regex.exec(line)) !== null) {
        if (match.index > last) {
            runs.push(new TextRun({ text: line.slice(last, match.index), size: baseSize }));
        }
        if (match[1] !== undefined) {
            runs.push(new TextRun({ text: match[1], bold: true, size: baseSize }));
        } else if (match[2] !== undefined) {
            runs.push(new TextRun({ text: match[2], italics: true, size: baseSize }));
        }
        last = match.index + match[0].length;
    }

    if (last < line.length) {
        runs.push(new TextRun({ text: line.slice(last), size: baseSize }));
    }

    return runs.length > 0 ? runs : [new TextRun({ text: line, size: baseSize })];
}

// ─── PDF generator ────────────────────────────────────────────────────────────

function generatePDF(text: string, referenceId: string, dateStr: string): Promise<Buffer> {
    return new Promise((resolve, reject) => {
        try {
            const doc = new PDFDocument({
                autoFirstPage: false,
                size: "A4",
                margins: { top: 90, bottom: 60, left: 50, right: 50 },
            });
            const chunks: Buffer[] = [];
            doc.on("data", (chunk: Buffer) => chunks.push(chunk));
            doc.on("end", () => resolve(Buffer.concat(chunks)));
            doc.on("error", reject);

            const logoPath = path.join(process.cwd(), "public", "new-logo.png");
            const logoExists = fs.existsSync(logoPath);

            const drawPageChrome = () => {
                const pageWidth = doc.page.width;

                if (logoExists) {
                    doc.save();
                    doc.image(logoPath, pageWidth - 110, 20, { width: 100 });
                    doc.restore();
                }

                doc.x = doc.page.margins.left;
                doc.y = doc.page.margins.top;
            };

            doc.on("pageAdded", () => {
                drawPageChrome();
            });

            doc.addPage();

            // ── Title block ──
            doc.fontSize(18).fillColor("#12A1A6").font("Helvetica-Bold").text("ExplainMyLetter Breakdown", { align: "center" });

            doc.moveDown(0.3);
            doc.fontSize(9).fillColor("#64748b").font("Helvetica").text(`Ref: ${referenceId}   |   Date: ${dateStr}`, { align: "right" });

            doc.moveDown(0.4);
            doc.moveTo(50, doc.y)
                .lineTo(doc.page.width - 50, doc.y)
                .strokeColor("#e2e8f0")
                .lineWidth(1)
                .stroke();
            doc.moveDown(0.8);

            const lines = text.trim().split("\n");

            for (const raw of lines) {
                const line = raw.trimEnd();

                if (!line) {
                    doc.moveDown(0.3);
                    continue;
                }

                if (/^---+$/.test(line.trim())) {
                    doc.moveDown(0.3);
                    doc.moveTo(50, doc.y)
                        .lineTo(doc.page.width - 50, doc.y)
                        .strokeColor("#e2e8f0")
                        .lineWidth(0.5)
                        .stroke();
                    doc.moveDown(0.3);
                    continue;
                }

                if (line.startsWith("### ")) {
                    doc.moveDown(0.4);
                    doc.fontSize(11)
                        .fillColor("#12A1A6")
                        .font("Helvetica-Bold")
                        .text(stripInline(line.slice(4)));
                    doc.moveDown(0.2);
                    continue;
                }

                if (line.startsWith("## ")) {
                    doc.moveDown(0.5);
                    doc.fontSize(13)
                        .fillColor("#12A1A6")
                        .font("Helvetica-Bold")
                        .text(stripInline(line.slice(3)));
                    doc.moveDown(0.15);
                    doc.moveTo(50, doc.y)
                        .lineTo(doc.page.width - 50, doc.y)
                        .strokeColor("#e2e8f0")
                        .lineWidth(0.5)
                        .stroke();
                    doc.moveDown(0.3);
                    continue;
                }

                if (line.startsWith("# ")) {
                    doc.moveDown(0.5);
                    doc.fontSize(15)
                        .fillColor("#12A1A6")
                        .font("Helvetica-Bold")
                        .text(stripInline(line.slice(2)));
                    doc.moveDown(0.15);
                    doc.moveTo(50, doc.y)
                        .lineTo(doc.page.width - 50, doc.y)
                        .strokeColor("#e2e8f0")
                        .lineWidth(1)
                        .stroke();
                    doc.moveDown(0.3);
                    continue;
                }

                const indentedBullet = line.match(/^(\s+)[-*]\s+(.*)/);
                if (indentedBullet) {
                    const depth = Math.floor(indentedBullet[1].length / 2);
                    const content = indentedBullet[2];
                    const boldMatch = content.match(/^\*\*(.+?)\*\*\s*(.*)/);
                    if (boldMatch) {
                        doc.fontSize(10)
                            .fillColor("#334155")
                            .font("Helvetica-Bold")
                            .text("•  " + stripInline(boldMatch[1]), { indent: 10 + depth * 16, lineGap: 2, continued: boldMatch[2].length > 0 });
                        if (boldMatch[2]) {
                            doc.fontSize(10)
                                .fillColor("#334155")
                                .font("Helvetica")
                                .text("  " + stripInline(boldMatch[2]), { lineGap: 2 });
                        }
                    } else {
                        doc.fontSize(10)
                            .fillColor("#334155")
                            .font("Helvetica")
                            .text("•  " + stripInline(content), { indent: 10 + depth * 16, lineGap: 2 });
                    }
                    doc.moveDown(0.12);
                    continue;
                }

                if (line.startsWith("- ") || line.startsWith("* ")) {
                    const content = line.slice(2);
                    const boldMatch = content.match(/^\*\*(.+?)\*\*\s*(.*)/);
                    if (boldMatch) {
                        doc.fontSize(10)
                            .fillColor("#334155")
                            .font("Helvetica-Bold")
                            .text("•  " + stripInline(boldMatch[1]), { indent: 10, lineGap: 2, continued: boldMatch[2].length > 0 });
                        if (boldMatch[2]) {
                            doc.fontSize(10)
                                .fillColor("#334155")
                                .font("Helvetica")
                                .text("  " + stripInline(boldMatch[2]), { lineGap: 2 });
                        }
                    } else {
                        doc.fontSize(10)
                            .fillColor("#334155")
                            .font("Helvetica")
                            .text("•  " + stripInline(content), { indent: 10, lineGap: 2 });
                    }
                    doc.moveDown(0.15);
                    continue;
                }

                const olMatch = line.match(/^(\d+)\.\s+(.*)/);
                if (olMatch) {
                    doc.fontSize(10)
                        .fillColor("#334155")
                        .font("Helvetica")
                        .text(`${olMatch[1]}.  ${stripInline(olMatch[2])}`, { indent: 10, lineGap: 2 });
                    doc.moveDown(0.15);
                    continue;
                }

                const termLabel = line.match(/^\*\*(.+?)\*\*\s*$/);
                if (termLabel) {
                    doc.moveDown(0.3);
                    doc.fontSize(11).fillColor("#0F233F").font("Helvetica-Bold").text(stripInline(termLabel[1]));
                    doc.moveDown(0.15);
                    continue;
                }

                const termWithText = line.match(/^\*\*(.+?)\*\*\s+(.*)/);
                if (termWithText) {
                    doc.moveDown(0.2);
                    doc.fontSize(10).fillColor("#12A1A6").font("Helvetica-Bold").text(stripInline(termWithText[1]));
                    if (termWithText[2]) {
                        doc.fontSize(10).fillColor("#334155").font("Helvetica").text(stripInline(termWithText[2]), { lineGap: 2 });
                    }
                    doc.moveDown(0.15);
                    continue;
                }

                doc.fontSize(10).fillColor("#334155").font("Helvetica").text(stripInline(line), { lineGap: 2 });
                doc.moveDown(0.2);
            }

            // ── Footer disclaimer — flows naturally with content, no absolute positioning ──
            doc.moveDown(1);
            doc.moveTo(50, doc.y)
                .lineTo(doc.page.width - 50, doc.y)
                .strokeColor("#e2e8f0")
                .lineWidth(0.5)
                .stroke();
            doc.moveDown(0.5);
            doc.fontSize(7).fillColor("#94a3b8").font("Helvetica").text(DISCLAIMER, {
                align: "center",
                lineGap: 2,
            });

            doc.end();
        } catch (err) {
            reject(err);
        }
    });
}
// ─── DOCX generator ───────────────────────────────────────────────────────────

async function generateDOCX(text: string, referenceId: string, dateStr: string): Promise<Buffer> {
    const children: Paragraph[] = [];
    const lines = text.split("\n");
    const LOGO_BASE64 = ""; 
    // ── Read logo if it exists ──
    const logoPath = path.join(process.cwd(), "public", "new-logo.png");
    const logoExists = fs.existsSync(logoPath);
    const logoData = logoExists ? fs.readFileSync(logoPath) : null;
    const imgBuffer = Buffer.from(LOGO_BASE64, 'base64');
    for (const raw of lines) {
        const line = raw.trimEnd();

        if (!line) {
            children.push(new Paragraph({ children: [], spacing: { after: 100 } }));
            continue;
        }

        if (line.startsWith("## ")) {
            children.push(
                new Paragraph({
                    children: [new TextRun({ text: stripInline(line.slice(3)), bold: true, size: 28, color: "12A1A6" })],
                    spacing: { before: 300, after: 120 },
                }),
            );
            continue;
        }

        if (line.startsWith("### ")) {
            children.push(
                new Paragraph({
                    children: [new TextRun({ text: stripInline(line.slice(4)), bold: true, size: 24, color: "12A1A6" })],
                    spacing: { before: 200, after: 100 },
                }),
            );
            continue;
        }

        if (line.startsWith("# ")) {
            children.push(
                new Paragraph({
                    children: [new TextRun({ text: stripInline(line.slice(2)), bold: true, size: 32, color: "12A1A6" })],
                    spacing: { before: 360, after: 160 },
                }),
            );
            continue;
        }

        if (line.startsWith("- ") || line.startsWith("* ")) {
            children.push(
                new Paragraph({
                    children: parseInlineDocx(line.slice(2)),
                    bullet: { level: 0 },
                    spacing: { after: 80 },
                }),
            );
            continue;
        }

        const olMatch = line.match(/^(\d+)\.\s+(.*)/);
        if (olMatch) {
            children.push(
                new Paragraph({
                    children: parseInlineDocx(olMatch[2]),
                    numbering: { reference: "eml-numbering", level: 0 },
                    spacing: { after: 80 },
                }),
            );
            continue;
        }

        if (/^---+$/.test(line.trim())) {
            children.push(
                new Paragraph({
                    children: [],
                    border: {
                        bottom: {
                            color: "e2e8f0",
                            space: 1,
                            style: BorderStyle.SINGLE,
                            size: 6,
                        },
                    },
                    spacing: { before: 160, after: 160 },
                }),
            );
            continue;
        }

        children.push(
            new Paragraph({
                children: parseInlineDocx(line),
                spacing: { after: 100 },
            }),
        );
    }

    const doc = new Document({
        numbering: {
            config: [
                {
                    reference: "eml-numbering",
                    levels: [
                        {
                            level: 0,
                            format: "decimal" as const,
                            text: "%1.",
                            alignment: AlignmentType.LEFT,
                            style: {
                                paragraph: { indent: { left: 360, hanging: 260 } },
                            },
                        },
                    ],
                },
            ],
        },
        sections: [
            {
                properties: {
                    page: {
                        size: { width: 11906, height: 16838 },
                        margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
                    },
                },
                headers: {
                    default: new Header({
                        children: [
                            // Row 1: Logo on the right
                            new Paragraph({
                                alignment: AlignmentType.RIGHT,
                                children: [
                                    ...(logoData
                                        ? [
                                              new ImageRun({
                                                  data: imgBuffer,
                                                  transformation: { width: 130, height: 50 },
                                                  type: "png",
                                              }),
                                          ]
                                        : [new TextRun({ text: "ExplainMyLetter", bold: true, color: "0d9488", size: 24 })]),
                                ],
                                spacing: { after: 60 },
                            }),
                            // Row 2: Ref info on the right
                            new Paragraph({
                                alignment: AlignmentType.RIGHT,
                                children: [
                                    new TextRun({
                                        text: `Ref: ${referenceId}  |  ${dateStr}`,
                                        color: "64748b",
                                        size: 16,
                                    }),
                                ],
                                spacing: { after: 0 },
                            }),
                        ],
                    }),
                },
                footers: {
                    default: new Footer({
                        children: [
                            new Paragraph({
                                alignment: AlignmentType.CENTER,
                                children: [new TextRun({ text: DISCLAIMER, color: "94a3b8", size: 14 })],
                            }),
                        ],
                    }),
                },
                children: [
                    new Paragraph({
                        alignment: AlignmentType.CENTER,
                        children: [
                            new TextRun({
                                text: "ExplainMyLetter Breakdown",
                                bold: true,
                                size: 36,
                                color: "0d9488",
                            }),
                        ],
                        spacing: { after: 240 },
                    }),
                    ...children,
                ],
            },
        ],
    });

    const buffer = await Packer.toBuffer(doc);
    return Buffer.from(new Uint8Array(buffer instanceof ArrayBuffer ? buffer : buffer));
}
